INSERT INTO public.lessons (id,course_id,title,content_type,url,file_path,article_content,estimated_minutes,sort_order) VALUES
  ('a1d10900-0000-4000-8000-000000000000','a1d00000-0000-4000-8000-000000000000','確認テスト ─ P/Lのざっくり読み','quiz',NULL,NULL,NULL,3,2),
  ('a1d20900-0000-4000-8000-000000000000','a1d00000-0000-4000-8000-000000000000','確認テスト ─ キャッシュと利益の違い','quiz',NULL,NULL,NULL,3,4)
INSERT INTO public.quiz_questions (lesson_id,question,option_a,option_b,option_c,option_d,correct_option,sort_order) VALUES
('a1d10900-0000-4000-8000-000000000000','P/Lの正体を一行で言うと、どれか。','会社が一年でいくら稼ぎ、いくら使い、いくら残したかの物語である','税務署や銀行が使う、全項目を覚えるべき専門文書である','単月の調子を一点で判断するための速報表である','資産と負債の残高を映した、今この瞬間の写真である','A',0),
('a1d10900-0000-4000-8000-000000000000','主任がP/Lをざっくり読むとき、まず見る三つはどれか。','経常利益・税引前利益・純利益','売上・営業利益・利益率','資産・負債・純資産','仕入・人件費・家賃','B',1),
('a1d10900-0000-4000-8000-000000000000','「売上は増えたのに利益率が下がった」ことから読めるのは、どれか。','売上の集計に誤りがあった','来年の売上が必ず落ちる','売上と利益のあいだで、費用が前より多く出ていっている','営業利益より経常利益を見るべきだった','C',2),
('a1d20900-0000-4000-8000-000000000000','利益とキャッシュの違いを一行で言うと、どれか。','利益は嘘の数字で、キャッシュだけが本当の数字である','利益は今ここの現金、キャッシュは未来の見込みである','利益は約束まで含めた「もうけの記録」、キャッシュは今ここにある「使える現金」である','利益もキャッシュも、動く時刻はいつも同じである','C',0),
('a1d20900-0000-4000-8000-000000000000','利益とキャッシュがズレる原因として本文が挙げる四つは、どれか。','売掛・買掛・在庫・設備投資','売上・費用・利益・利益率','入り・出・タイミング・残高','税金・借入・配当・減価','A',1),
('a1d20900-0000-4000-8000-000000000000','「黒字倒産」とは、どれか。','赤字が続いて資本が尽き、会社が立ち行かなくなること','利益は出ているのに、手元の現金が尽きて会社が立ち行かなくなること','在庫を売り切って現金化し、黒字に転じること','売掛の入金が早まって、現金が余ること','B',2);
